  const ayahs: AyahProps[] = [
    { ayahId: 100, surahNumber: 2, pageNumber: 15, isComplete: true, continuesFromPrev: true, textData: "۴لاَخِرَةُ عِندَ ۰للَّهِ خَالِصَةً مِّن دُونِ ۱لنَّاسِ فَتَمَنَّوُاْ ۴لْمَوْتَ إِن كُنتُمْ صَـٰدِقِينَؐ" },
    { ayahId: 101, surahNumber: 2, pageNumber: 15, isComplete: true, continuesFromPrev: false, textData: "وَلَنْ يَّتَمَنَّوْهُ أَبَداَۢ بِمَا قَدَّمَــتَ اَيْدِيهِمْؐ وَاللَّهُ عَلِيمٛ بِالظَّـٰلِمِينَؐ" },
    { ayahId: 102, surahNumber: 2, pageNumber: 15, isComplete: true, continuesFromPrev: false, textData: "وَلَتَجِدَنَّهُمُ; أَحْرَصَ ۰لنَّاسِ عَلَيٰ حَيَوٰةٍؐ وَمِنَ ۰لذِينَ أَشْرَكُواْ يَوَدُّ أَحَدُهُمْ لَوْ يُعَمَّرُ أَلْفَ سَنَةٍؐ وَمَا هُوَ بِمُزَحْزۣحِهِ” مِنَ ۰لْعَذَابببِ أَنْ يُّعَمَّرَؐ وَاللَّهُ بَصِيرٛ بِمَا يَعْمَلُونَؐ" },
    { ayahId: 103, surahNumber: 2, pageNumber: 15, isComplete: true, continuesFromPrev: false, textData: "قُلْ مَن كَانَ عَدُوّاً لِّجِبْرۣيلَ فَإِنَّهُ„ نَزَّلَهُ„ عَلَيٰ قَلْبِكَ بِإِذْنِ ۱للَّهِ مُصَدِّقاً لِّمَا بَيْنَ يَدَيْهِ وَهُديً وَبُشْرۭيٰ لِلْمُومِنِينَؐ" },
    { ayahId: 104, surahNumber: 2, pageNumber: 15, isComplete: true, continuesFromPrev: false, textData: "مَن كَانَ عَدُوّاً لِّلهِ وَمَلَئِكَتِهِ” وَرُسُلِهِ” وَجِبْرۣيلَ وَمِيكَـٰٓئِلَ فَإِنَّ ۰للَّهَ عَدُوٌّ لِّلْكۭــٰفِـرۣينَؐ" },
    { ayahId: 105, surahNumber: 2, pageNumber: 15, isComplete: true, continuesFromPrev: false, textData: "وَلَقَدَ اَنزَلْنَآ إِلَيْكَ ءَايَــٰــتٙ بَيِّنَــٰــتٍؐ وَمَا يَكْفُرُ بِهَآ إِلاَّ ۰لْفَــٰسِقُونَؐ" },
    { ayahId: 106, surahNumber: 2, pageNumber: 15, isComplete: true, continuesFromPrev: false, textData: "أَوَكُلَّمَا عَــٰهَدُواْ عَهْداً نَّبَذَهُ„ فَرۣيقٌ مِّنْهُمؐ بَلَ اَكْثَرُهُمْ لاَ يُومِنُونَؐ ®" },
    { ayahId: 107, surahNumber: 2, pageNumber: 15, isComplete: true, continuesFromPrev: false, textData: "وَلَمَّا جَآءَهُمْ رَسُولٌ مِّنْ عِندِ ۱للَّهِ مُصَدِّقٌ لِّمَا مَعَهُمْ نَبَذَ فَرۣيقٌ مِّنَ ۰لذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ كِتَــٰــبَ ۰للَّهِ وَرَآءَ ظُهُورۣهِمْ كَأَنَّهُمْ لاَ يَعْلَمُونَؐ" },
    { ayahId: 108, surahNumber: 2, pageNumber: 15, isComplete: false, continuesFromPrev: false, textData: "وَاتَّبَعُواْ مَا تَتْلُواْ ۴لشَّيَـٰطِينُ عَلَيٰ مُلْكِ سُلَيْمَـٰنَؐ وَمَا كَفَرَ سُلَيْمَـٰنُؐ وَچَكِنَّ ۰لشَّيَـٰطِينَ كَفَرُواْ يُعَلِّمُونَ" }
  ];

